var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"MODER_BOSS_NULL_NULL","text":{"KOREA":"<color=#ff3636>손상 부위 수리 중. 교전 속행 가능.</color>","JPN":"<color=#ff3636>損傷部位を修理中。交戦続行可能。</color>","ENG":"<color=#ff3636>Repairing damage. Ready to engage.</color>","TWN":"<color=#ff3636>正在維修損壞部位，可以繼續交戰。</color>"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"MODER_BOSS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MODER_BOSS_NULL_NULL","text":{"KOREA":"<color=#ff3636>적성 개체를 섬멸합니다.</color>","JPN":"<color=#ff3636>敵性個体を殲滅します。</color>","ENG":"<color=#ff3636>Eliminating hostile entity.</color>","TWN":"<color=#ff3636>殲滅敵人個體。</color>"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"MODER_BOSS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"제길, 뭐 저딴 게 다 있어……!","JPN":"くそ、化け物かよ……！","ENG":"Damn it, what even is this thing...?!","TWN":"該死，怎麼會有那種東西！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"특수탄을 이렇게나 때려 박았는데, 꿈쩍도 안 하잖아!","JPN":"特殊弾をあれほどぶち込んだのに、びくともしない！","ENG":"I pumped it full of special bullets and it didn't even flinch!","TWN":"打了這麼多特殊彈，居然一點反應都沒有！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"깡통 로봇 주제에 더럽게 단단하네……!","JPN":"ボロ缶ロボットのくせに硬すぎだろ……！","ENG":"For a tin can robot, it's ridiculously tough...!","TWN":"這破鐵桶機器人居然這麼硬！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ROSE_BETA_MAID_OFF","text":{"KOREA":"하우스홀드 네트워크 갱신…….","JPN":"ハウスホールドネットワーク更新……","ENG":"Household Network updated...","TWN":"家用網路更新……"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ROSE_BETA_MAID_OFF","text":{"KOREA":"대 침식 4종 섬멸 병기, 모더레이터로군요.","JPN":"対侵食第4種殲滅兵器、モデレーターですね。","ENG":"That's the Moderator, the Anti-Corruption annihilator designed for defeating Category 4 C.O.s.","TWN":"是對抗侵蝕4類殲滅兵器，仲裁者。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ROSE_BETA_MAID_OFF","text":{"KOREA":"개발 목적은 어떠한 조건에서도 작전 수행이 가능하도록 만들어진 병기.","JPN":"どのような条件下でも作戦遂行を可能にすることを開発目的として作られた兵器。","ENG":"It was developed to operate under any condition, no matter the environment.","TWN":"開發目的是為了在任何條件下都能執行作戰任務的兵器。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ROSE_BETA_MAID_OFF","text":{"KOREA":"아마도 생체 강철 시스템을 통해, 자가 회복이 가능한 모양입니다.","JPN":"おそらく生体鋼鉄システムを通じ、自己回復も可能かと。","ENG":"Looks like it's equipped with a bio-steel system that lets it self-repair.","TWN":"可能是通過生物鋼鐵系統，實現了自我恢復的功能。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"4종 섬멸 병기라고?","JPN":"第4種殲滅兵器だと？","ENG":"An annihilator designed for defeating Category 4 C.O.s?","TWN":"4類殲滅武器？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"그럼, 저 커다란 깡통 로봇이 4종 침식체 수준이란 말이야?","JPN":"じゃあ、あのデカいボロ缶ロボットが第4種侵食体レベルってこと？","ENG":"You're telling me that giant robot is as dangerous as a Category 4 C.O.?","TWN":"那麼，那台巨大的鐵罐機器人是4類侵蝕體級別的嗎？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"ROSE_BETA_MAID_OFF","text":{"KOREA":"그렇습니다, 라이카.","JPN":"そのとおりです、ライカ。","ENG":"That's correct, Laika.","TWN":"是的，萊卡。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"ROSE_BETA_MAID_OFF","text":{"KOREA":"유효 타개책은 CRF에 의한 직접 공격으로 코어 부분을 파괴하는 것.","JPN":"有効な打開策はCRFによる直接攻撃でコアを破壊すること。","ENG":"The only viable option is using CRF to directly strike and destroy its core.","TWN":"有效的解決方案是通過CRF的直接攻擊來摧毀核心部分。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"젠장, CRF라고? 우리 중엔 카운터가 없잖아?","JPN":"くそ、CRFだと？　こっちにはカウンターがいないってのに！","ENG":"Damn it, did you just say CRF? But we don't even have a Counter with us!","TWN":"喂，CRF？我們之間可沒有制裁者啊？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L23_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"결국, 어떻게든 지근거리에서 코어에 이터니움 특수탄을 때려박는 수밖에 없나?","JPN":"結局、なんとかして至近距離でコアにエタニウム特殊弾をぶち込むしかないのか？","ENG":"So the only way is to get in close and shove some Eternium bullets into the core?","TWN":"最終，看來只能在近距離用永恆之金特殊彈打擊核心了。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"역시 안 되겠어요, 라이카.","JPN":"やっぱりダメです、ライカ。","ENG":"That won't work, Laika.","TWN":"果然不行啊，萊卡。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"다들 비켜요, <color=#ffd34c>망원경</color>을 쓸게요!","JPN":"みんなどいてください、<color=#ffd34c>望遠鏡</color>を使います！","ENG":"Everyone get back, I'll use the <color=#ffd34c>Telescope</color>!","TWN":"大家讓開，我要用<color=#ffd34c>望遠鏡</color>了！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"그거라면 어떻게든 여길 돌파할 수 있겠지……!","JPN":"これならなんとかここを突破できるはず……！","ENG":"That should be enough to break through...!","TWN":"那樣的話，總可以突破這裡吧…！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"기다려, 허접 꼬맹아!","JPN":"待ちなさい、ヘタクソガキ！","ENG":"Hold it, you scrawny brat!","TWN":"等等，臭小鬼！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"너희들이 도착할 곳은 통신조차 닿지 않는 고심도 이면세계야.","JPN":"あんたたちの行き先は、通信すら届かない高深度裏世界。","ENG":"Where you're headed is the hyperdepths of the Counterside that even comms can't reach.","TWN":"你們要去的地方是連通訊都沒有的高深度異界。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"망원경은 그곳에서 너희에게 길을 알려줄 유일한 이정표 같은 거라고!","JPN":"望遠鏡はそこであんたたちを案内してくれる唯一の道しるべなのよ！","ENG":"The Telescope is the only guide you'll have once you're in there!","TWN":"望遠鏡是唯一能在那裡為你們指引道路的路標！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L34_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"그곳에서 무슨 일이 발생할지 모르는데, 여기서 그걸 낭비할 수는 없어!","JPN":"何があるかもわからないのに、ここでそれを無駄遣いするわけにはいかない！","ENG":"You don't know what you'll run into, so you can't afford to waste it now!","TWN":"不知道在那裡會發生什麼事？，所以不能在這裡浪費！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L35_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"그렇지만 저건 4종 침식체와 맞먹는 병기잖아요!","JPN":"でもあれは第4種侵食体並みの兵器なんでしょう！","ENG":"But that thing's on par with a Category 4 C.O.!","TWN":"可是那是相當於4類侵蝕體的兵器啊！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L36_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"이대로 라면, 타이밍을 맞추지 못할 수도 있다고요!","JPN":"このままだと、間に合わないかもしれません！","ENG":"If we screw up the timing here, we're toast!","TWN":"照這樣下去，可能會失去好時機！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};